import{_ as a,o as t,c as s,a2 as i}from"./chunks/framework.CH-YxFqP.js";const n="/nginx-reverse-emby/screenshots/cloudflare-token-permissions.png",b=JSON.parse('{"title":"证书管理","description":"","frontmatter":{},"headers":[],"relativePath":"reference/certificates.md","filePath":"reference/certificates.md","lastUpdated":1781350447000}'),l={name:"reference/certificates.md"};function r(d,e,p,o,c,h){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="证书管理" tabindex="-1">证书管理 <a class="header-anchor" href="#证书管理" aria-label="Permalink to &quot;证书管理&quot;">​</a></h1><p>控制面可以为代理规则管理 ACME 证书和证书材料。</p><p>证书材料会随面板数据一起持久化。不要把证书私钥、DNS API Token 或 <code>panel/data/</code> 里的内容提交到仓库。</p><h2 id="http-验证" tabindex="-1">HTTP 验证 <a class="header-anchor" href="#http-验证" aria-label="Permalink to &quot;HTTP 验证&quot;">​</a></h2><p>HTTP 验证也就是 HTTP-01。它适合普通单域名证书，例如：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://emby.example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>使用 HTTP-01 时，需要满足：</p><ul><li>域名已经解析到承载规则的 VPS。</li><li>VPS 公网可以访问 <code>80</code> 端口。</li><li>HTTPS 访问还需要放行 <code>443</code> 端口。</li></ul><p>HTTP 规则保存后，Agent 会在同步配置时自动申请证书；手动重试签发时，也是让 Agent 重新进入待签发状态。</p><h2 id="dns-验证" tabindex="-1">DNS 验证 <a class="header-anchor" href="#dns-验证" aria-label="Permalink to &quot;DNS 验证&quot;">​</a></h2><p>当代理无法暴露 <code>80</code> 端口，或需要通配符证书时，推荐使用 DNS 验证。</p><p>Cloudflare 可通过环境变量配置 DNS 提供商和令牌：</p><div class="language-ini vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ACME_DNS_PROVIDER</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=cf</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CF_TOKEN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=your-cloudflare-api-token</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Cloudflare API Token 需要配置这些权限：</p><table tabindex="0"><thead><tr><th>选择项</th><th>用途</th></tr></thead><tbody><tr><td><code>区域 / 区域 / 读取</code></td><td>读取域名所属区域。</td></tr><tr><td><code>区域 / DNS / 读取</code></td><td>读取 DNS 记录。</td></tr><tr><td><code>区域 / DNS / 编辑</code></td><td>创建和删除证书验证用的 DNS 记录。</td></tr></tbody></table><p>区域资源选择 <strong>包括 / 特定区域 / 你的域名</strong>。客户端 IP 地址筛选保持默认即可。</p><p><img src="`+n+'" alt="Cloudflare API Token 权限配置"></p><p>不要提交 DNS 令牌或私钥。</p><h2 id="relay-证书" tabindex="-1">Relay 证书 <a class="header-anchor" href="#relay-证书" aria-label="Permalink to &quot;Relay 证书&quot;">​</a></h2><p>Relay 监听器默认使用系统自动签发的 Relay CA 和监听证书。普通用户不需要手动创建 Relay 证书，也不需要维护 Pin Set。</p><p>只有你需要完全自定义 Relay TLS 信任材料时，才在 Relay 监听器里把证书来源切到“绑定已有证书”，并在高级信任策略里手动配置 Pin 或 CA。</p><h2 id="http-3" tabindex="-1">HTTP/3 <a class="header-anchor" href="#http-3" aria-label="Permalink to &quot;HTTP/3&quot;">​</a></h2><p>设置下面的变量后，HTTPS 入口可以同时启用 HTTP/3：</p><div class="language-ini vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NRE_HTTP3_ENABLED</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=true</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>',24)])])}const m=a(l,[["render",r]]);export{b as __pageData,m as default};
